using System;
using System.Text.Json;

namespace AvatarBuilder.Modules.Vision.MediaPipe.Reconstruction.Stereo;

public static class MediaPipeStereoFaceViewerPage
{
	private static readonly JsonSerializerOptions JsonOptions = new JsonSerializerOptions(JsonSerializerDefaults.Web);

	public static string Build(MediaPipeStereoFaceModel model)
	{
		ArgumentNullException.ThrowIfNull(model, "model");
		string text = JsonSerializer.Serialize(model, JsonOptions).Replace("</", "<\\/", StringComparison.Ordinal);
		return "<!doctype html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width,initial-scale=1\">\n  <title>Calibrated Stereo Face</title>\n  <style>\n    :root{color-scheme:dark;font-family:\"Segoe UI\",Arial,sans-serif;background:#061019;color:#e7f4ff}\n    *{box-sizing:border-box}body{margin:0;min-height:100vh;background:#061019}\n    header{height:54px;display:flex;align-items:center;gap:8px;padding:8px 12px;border-bottom:1px solid #254052;background:#0a1721}\n    button{color:#e7f4ff;background:#10283a;border:1px solid #397397;padding:8px 12px;cursor:pointer}\n    button[aria-pressed=\"true\"]{background:#15567a;border-color:#63c9ff}.spacer{flex:1}\n    .layout{height:calc(100vh - 54px);display:grid;grid-template-columns:minmax(0,1fr) 350px}\n    .stage{position:relative;min-width:0;overflow:hidden}canvas{width:100%;height:100%;display:block;background:#040b11;touch-action:none}\n    .hint{position:absolute;left:14px;top:12px;padding:8px 10px;background:#07121dcc;border:1px solid #20394b;color:#b9d7ef;font-size:12px;pointer-events:none}\n    aside{overflow:auto;padding:16px;border-left:1px solid #254052;background:#08141d}h1{margin:0 0 4px;font-size:20px;letter-spacing:0}\n    h2{margin:20px 0 8px;font-size:13px;color:#80e0a4;letter-spacing:0}p{margin:5px 0;line-height:1.4}.muted{color:#9ebdd2;font-size:12px}.status{color:#ffd27a}\n    .metric{display:grid;grid-template-columns:1fr auto;gap:10px;padding:7px 0;border-bottom:1px solid #193044;font-size:12px}.metric strong{color:#dff5ff;font-variant-numeric:tabular-nums}\n    .legend{display:grid;gap:7px;font-size:12px}.swatch{display:inline-block;width:18px;height:2px;margin-right:8px;vertical-align:middle}\n    .note{margin-top:16px;padding:10px;border:1px solid #2c627f;color:#bfe9ff;background:#081b27;font-size:12px;line-height:1.4}\n    @media(max-width:800px){.layout{grid-template-columns:1fr;grid-template-rows:minmax(420px,65vh) auto;height:auto}aside{border-left:0;border-top:1px solid #254052}}\n  </style>\n</head>\n<body>\n  <header><button id=\"dense\" aria-pressed=\"true\">Dense Surface</button><button id=\"points\" aria-pressed=\"true\">478 Anchors</button><button id=\"wire\" aria-pressed=\"true\">Anchor Wireframe</button><button id=\"reset\">Reset 3D View</button><span class=\"spacer\"></span><button id=\"updates\" aria-pressed=\"true\">Live Updates</button><button id=\"refresh\">Refresh Now</button></header>\n  <main class=\"layout\">\n    <section class=\"stage\"><canvas id=\"view\"></canvas><div class=\"hint\">Drag to rotate; wheel to zoom. Coordinates and dimensions are calibrated inches.</div></section>\n    <aside><h1>Calibrated Stereo Face</h1><p><strong id=\"subject\"></strong></p><p class=\"muted\" id=\"updated\"></p><p class=\"status\" id=\"status\"></p><h2>Physical Measurements</h2><div id=\"metrics\"></div>\n      <h2>Evidence</h2><div class=\"legend\"><div><span class=\"swatch\" style=\"background:#66e8b0\"></span>Stable image-matched dense surface</div><div><span class=\"swatch\" style=\"background:#62d5ff\"></span>Stable MediaPipe stereo anchor</div><div><span class=\"swatch\" style=\"background:#ffd166\"></span>Partial or expression geometry</div><div><span class=\"swatch\" style=\"background:#405869\"></span>Underconstrained</div></div>\n      <div class=\"note\">The 478 anchors and dense surface are separate evidence layers. Dense points come from calibrated image matches between the two cameras, then pass forward/backward flow, epipolar, and reprojection checks. Rejected areas are left empty rather than filled with a generic head.</div>\n    </aside>\n  </main>\n  <script>\n    const model=" + text + ",canvas=document.getElementById('view'),ctx=canvas.getContext('2d',{alpha:false}),key='avatarBuilder.stereoFaceView';\n    let saved={};try{saved=JSON.parse(localStorage.getItem(key)||'{}')}catch{}\n    const view={yaw:Number.isFinite(saved.yaw)?saved.yaw:-.32,pitch:Number.isFinite(saved.pitch)?saved.pitch:.06,zoom:Number.isFinite(saved.zoom)?saved.zoom:.78,dense:saved.dense!==false,points:saved.points!==false,wire:saved.wire!==false,updates:saved.updates!==false};\n    let dragging=false,lastX=0,lastY=0;const finite=v=>Number.isFinite(v)?v:0,fmt=(v,d=2)=>finite(v).toFixed(d),save=()=>localStorage.setItem(key,JSON.stringify(view));\n    const pressed=(id,v)=>document.getElementById(id).setAttribute('aria-pressed',v?'true':'false'),metric=(l,v)=>`<div class=\"metric\"><span>${l}</span><strong>${v}</strong></div>`;\n    document.getElementById('subject').textContent=model.subjectDisplayName||model.subjectId||'No profile';document.getElementById('updated').textContent=model.updatedAtUtc?`Updated ${new Date(model.updatedAtUtc).toLocaleString()}`:'Waiting for first accepted pair';document.getElementById('status').textContent=model.status||'';\n    document.getElementById('metrics').innerHTML=metric('Accepted synchronized frames',Number(model.acceptedFrameCount||0).toLocaleString())+metric('Rejected frames',Number(model.rejectedFrameCount||0).toLocaleString())+metric('Dense surface samples',`${Number(model.denseMeasuredVertexCount||0).toLocaleString()} / ${Number(model.denseMaximumVertexCount||0).toLocaleString()}`)+metric('Dense observations',Number(model.denseObservationCount||0).toLocaleString())+metric('Dense samples stable',`${fmt(model.denseStableVertexPercent,1)}%`)+metric('Rejected dense measurements',Number(model.rejectedDensePointCount||0).toLocaleString())+metric('Anchor observations',Number(model.directObservationCount||0).toLocaleString())+metric('Stable anchors',`${fmt(model.confidentVertexPercent,1)}%`)+metric('Median anchor spread',`${fmt(model.medianVertexDeviationInches,3)} in`)+metric('Face width',`${fmt(model.faceWidthInches)} in`)+metric('Face height',`${fmt(model.faceHeightInches)} in`)+metric('Measured depth span',`${fmt(model.measuredDepthInches)} in`)+metric('Camera baseline',`${fmt(model.baselineInches)} in`);\n    function rotate(p){const cy=Math.cos(view.yaw),sy=Math.sin(view.yaw),cp=Math.cos(view.pitch),sp=Math.sin(view.pitch),x=cy*p.x+sy*p.z,z=-sy*p.x+cy*p.z;return{x,y:cp*p.y-sp*z,z:sp*p.y+cp*z}}\n    function color(v,a=1){if(v.evidenceClass==='directly-measured')return`rgba(98,213,255,${a})`;if(v.evidenceClass==='partially-measured'||v.evidenceClass==='expression-only')return`rgba(255,209,102,${a})`;return`rgba(64,88,105,${a})`}\n    function draw(){const w=canvas.clientWidth,h=canvas.clientHeight;ctx.fillStyle='#040b11';ctx.fillRect(0,0,w,h);const vertices=(model.vertices||[]).map(v=>({...v,r:rotate({x:finite(v.xInches),y:finite(v.yInches),z:finite(v.zInches)})})),dense=(model.denseVertices||[]).map(v=>({...v,r:rotate({x:finite(v.xInches),y:finite(v.yInches),z:finite(v.zInches)})})),usable=vertices.filter(v=>Number(v.directObservationCount||0)>0),bounds=view.dense&&dense.length?[...usable,...dense]:usable;if(!bounds.length){ctx.fillStyle='#9ebdd2';ctx.font='16px Segoe UI';ctx.textAlign='center';ctx.fillText('Start Build 3D Face with both calibrated cameras running.',w/2,h/2);return}let minX=Infinity,maxX=-Infinity,minY=Infinity,maxY=-Infinity;for(const v of bounds){minX=Math.min(minX,v.r.x);maxX=Math.max(maxX,v.r.x);minY=Math.min(minY,v.r.y);maxY=Math.max(maxY,v.r.y)}const span=Math.max(.5,maxX-minX,maxY-minY),scale=Math.min(w,h)*view.zoom/span,cx=(minX+maxX)/2,cy=(minY+maxY)/2,project=r=>({x:w/2+(r.x-cx)*scale,y:h/2-(r.y-cy)*scale,z:r.z}),projected=vertices.map(v=>({...v,p:project(v.r)})),projectedDense=dense.map(v=>({...v,p:project(v.r)}));\n      if(view.dense){projectedDense.sort((a,b)=>a.p.z-b.p.z);for(const v of projectedDense){const stable=v.evidenceClass==='directly-measured',expression=v.evidenceClass==='expression-only';ctx.fillStyle=stable?'rgba(102,232,176,.82)':expression?'rgba(255,209,102,.50)':'rgba(98,213,255,.48)';ctx.beginPath();ctx.arc(v.p.x,v.p.y,stable ? .78 : .55,0,Math.PI*2);ctx.fill()}}\n      if(view.wire){ctx.lineWidth=.65;for(const edge of model.topologyEdges||[]){const a=projected[edge.fromIndex],b=projected[edge.toIndex];if(!a||!b||(!a.directObservationCount&&!b.directObservationCount))continue;const alpha=(a.evidenceClass==='underconstrained'||b.evidenceClass==='underconstrained')?.12:.48;ctx.strokeStyle=color(a,alpha);ctx.beginPath();ctx.moveTo(a.p.x,a.p.y);ctx.lineTo(b.p.x,b.p.y);ctx.stroke()}}\n      if(view.points){projected.sort((a,b)=>a.p.z-b.p.z);for(const v of projected){if(!v.directObservationCount)continue;ctx.fillStyle=color(v,.9);ctx.beginPath();ctx.arc(v.p.x,v.p.y,v.evidenceClass==='directly-measured'?1.25:.9,0,Math.PI*2);ctx.fill()}}}\n    function resize(){const dpr=Math.min(2,window.devicePixelRatio||1),r=canvas.getBoundingClientRect();canvas.width=Math.max(1,Math.round(r.width*dpr));canvas.height=Math.max(1,Math.round(r.height*dpr));ctx.setTransform(dpr,0,0,dpr,0,0);draw()}\n    function toggle(id,name){view[name]=!view[name];pressed(id,view[name]);save();draw()}document.getElementById('dense').onclick=()=>toggle('dense','dense');document.getElementById('points').onclick=()=>toggle('points','points');document.getElementById('wire').onclick=()=>toggle('wire','wire');document.getElementById('updates').onclick=()=>{view.updates=!view.updates;pressed('updates',view.updates);save()};document.getElementById('refresh').onclick=()=>location.reload();document.getElementById('reset').onclick=()=>{view.yaw=-.32;view.pitch=.06;view.zoom=.78;save();draw()};pressed('dense',view.dense);pressed('points',view.points);pressed('wire',view.wire);pressed('updates',view.updates);\n    canvas.addEventListener('pointerdown',e=>{dragging=true;lastX=e.clientX;lastY=e.clientY;canvas.setPointerCapture(e.pointerId)});canvas.addEventListener('pointermove',e=>{if(!dragging)return;view.yaw+=(e.clientX-lastX)*.008;view.pitch=Math.max(-1.45,Math.min(1.45,view.pitch+(e.clientY-lastY)*.008));lastX=e.clientX;lastY=e.clientY;draw()});canvas.addEventListener('pointerup',()=>{dragging=false;save()});canvas.addEventListener('wheel',e=>{e.preventDefault();view.zoom=Math.max(.18,Math.min(4,view.zoom*Math.exp(-e.deltaY*.001)));save();draw()},{passive:false});new ResizeObserver(resize).observe(canvas);setInterval(()=>{if(view.updates&&!dragging)location.reload()},2500);\n  </script>\n</body>\n</html>";
	}
}
